class Solution:
    def deleteAndEarn(self, nums):
        from collections import Counter
        cnt = Counter(nums)
        vals = sorted(cnt)
        from functools import lru_cache
        @lru_cache(maxsize=None)
        def best(idx):
            if idx >= len(vals):
                return 0
            v = vals[idx]
            skip = best(idx + 1)
            nxt = idx + 1
            while nxt < len(vals) and vals[nxt] == v + 1:
                nxt += 1
            take = v * cnt[v] + best(nxt)
            return max(skip, take)
        return best(0)

