var deleteAndEarn = function(nums) {
    const cnt = new Map();
    let mx = 0;
    for (const v of nums) {
        cnt.set(v, (cnt.get(v) || 0) + 1);
        if (v > mx) mx = v;
    }
    const gain = new Array(mx + 1).fill(0);
    for (const [v, c] of cnt) gain[v] = v * c;
    let prev2 = 0, prev1 = 0;
    for (let v = 1; v <= mx; v++) {
        const cur = Math.max(prev1, prev2 + gain[v]);
        prev2 = prev1;
        prev1 = cur;
    }
    return prev1;
};
